package com.hospital.management.validation;import com.hospital.management.model.MedicalRecordForm;import java.math.BigDecimal;import java.util.regex.*;
/** Field-level validation for clinical text and reasonable vital-sign ranges. */
public class MedicalRecordValidator {private static final Pattern BP=Pattern.compile("^(\\d{2,3})/(\\d{2,3})$");public ValidationResult validate(MedicalRecordForm f){ValidationResult r=new ValidationResult();if(f==null){r.addError("form","Medical record details are required");return r;}if(f.getAppointmentId()==null||f.getAppointmentId()<=0)r.addError("appointmentId","Valid appointment is required");required(f.getSymptoms(),"symptoms",2000,r);required(f.getDiagnosis(),"diagnosis",2000,r);max(f.getTreatmentNotes(),"treatmentNotes",4000,r);max(f.getAllergies(),"allergies",1000,r);pressure(f.getBloodPressure(),r);decimal(f.getTemperature(),"temperature",new BigDecimal("30"),new BigDecimal("45"),2,r);decimal(f.getWeight(),"weight",BigDecimal.ZERO,new BigDecimal("500"),2,r);decimal(f.getHeight(),"height",BigDecimal.ZERO,new BigDecimal("300"),2,r);return r;}private void required(String v,String k,int max,ValidationResult r){int n=v==null?0:v.trim().length();if(n<3||n>max)r.addError(k,"Must contain 3-"+max+" characters");}private void max(String v,String k,int max,ValidationResult r){if(v!=null&&v.length()>max)r.addError(k,"Must not exceed "+max+" characters");}private void pressure(String v,ValidationResult r){if(v==null||v.isBlank())return;Matcher m=BP.matcher(v.trim());if(!m.matches()){r.addError("bloodPressure","Use systolic/diastolic format, for example 120/80");return;}int s=Integer.parseInt(m.group(1)),d=Integer.parseInt(m.group(2));if(s<50||s>250||d<30||d>150||s<=d)r.addError("bloodPressure","Enter reasonable blood pressure with systolic greater than diastolic");}private void decimal(String v,String k,BigDecimal min,BigDecimal max,int scale,ValidationResult r){if(v==null||v.isBlank())return;try{BigDecimal n=new BigDecimal(v.trim());if(n.scale()>scale||n.compareTo(min)<=0||n.compareTo(max)>0)throw new NumberFormatException();}catch(NumberFormatException e){r.addError(k,"Enter a valid value within the allowed range");}}}
